findNumberTriplets (a, b, c) = nub [ (x, y, z) | 
    p <- permutations [1..9], 
    let x = toNumber (take 3 p),
    let y = toNumber (take 3 $ drop 3 p),
    let z = toNumber (drop 6 p),
    a * y == b * x, 
    a * z == c * x ]

toNumber :: [Int] -> Int
toNumber = foldl (\acc x -> acc * 10 + x) 0
